const output = $('update system').first().json.stdout
let message = "";
let status = "✅";
const logSnippet = output.slice(-1000);
const userId = "664803448629493816"; // Ganti dengan user Discord yang ingin ditag
const mention = `<@${userId}>`;

if (output.toLowerCase().includes("error") || output.toLowerCase().includes("failed")) {
  status = "❌";
  message = `\`\`\`\n${logSnippet}\n\`\`\`\n❌ Update failed!\n${mention}`;
} else if (output.toLowerCase().includes("a reboot is required")) {
  status = "🔄";
  message = `\`\`\`\n${logSnippet}\n\`\`\`\n🔄 Update completed but reboot is required.\n${mention}`;
} else {
  status = "✅";
  message = `\`\`\`\n${logSnippet}\n\`\`\`\n✅ System updated successfully!`;
}

return [{
  json: {
    status,
    message
  }
}];

const rawLog = $input.first().json.stdout;  // log input dari node sebelumnya

const updatedImages = [];
const failedImages = [];

const lines = rawLog.split("\n");

for (let i = 0; i < lines.length; i++) {
  const line = lines[i].trim();

  // Cek baris "Pulling image"
  if (line.startsWith("[*] Pulling image:")) {
    const image = line.replace("[*] Pulling image: ", "").trim();
    const statusLine = lines[i + 3] || "";  // Baris ke-3 setelah ini biasanya status
    const errorLine = lines[i + 1] || "";   // Jika error, muncul setelah ini

    if (statusLine.includes("Image is up to date")) {
      // Lewatkan (tidak perlu dicatat)
    } else if (errorLine.includes("Error response from daemon")) {
      failedImages.push(`${image} ❌`);
    } else {
      updatedImages.push(`${image} ✅`);
    }
  }
}

// Format pesan
const startedAt = rawLog.match(/Started at (.+?) ===/i)?.[1] || "Unknown";
const completedAt = rawLog.match(/Completed at (.+?) ===/i)?.[1] || "Unknown";

let message = `🛠️ **Docker Auto Update Summary**\n\n`;
message += `🕓 **Started**: ${startedAt}\n✅ **Completed**: ${completedAt}\n\n`;

if (updatedImages.length > 0) {
  message += `🔄 **Updated Images:**\n${updatedImages.map(i => `• ${i}`).join("\n")}\n\n`;
}

if (failedImages.length > 0) {
  message += `❗ **Failed Pulls:**\n${failedImages.map(i => `• ${i}`).join("\n")}\n\n`;
}

if (updatedImages.length === 0 && failedImages.length === 0) {
  message += `📦 All containers already up to date.\n`;
}

return [
  {
    json: {
      content: message  // Output ke Discord node
    }
  }
];

